import redis
from rediscluster import RedisCluster
from typing import Dict

class DistributedCache:
    def __init__(self, startup_nodes: list):
        self.redis_client = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

    def store_data(self, key: str, value: str, ttl: int) -> None:
        self.redis_client.setex(key, ttl, value)

    def retrieve_data(self, key: str) -> str:
        return self.redis_client.get(key)

